```bash
applypatch << 'PATCH'
*** Begin Patch
*** Update File: llvm/lib/Transforms/Utils/Local.cpp
@@
     if (II->isLifetimeStartOrEnd()) {
       auto *Arg = II->getArgOperand(1);
       // If the only uses of the alloca are lifetime intrinsics, then the
       // intrinsics are dead.
-      return llvm::all_of(Arg->users(), [](User *U) {
-        return isa<LifetimeIntrinsic>(U);
-      });
+      // If the value does not have a materialized use list, there are no recorded
+      // uses to inspect, so treat the lifetime intrinsic as dead.
+      if (!Arg->hasUseList())
+        return true;
+      return llvm::all_of(Arg->users(), [](User *U) {
+        return isa<LifetimeIntrinsic>(U);
+      });
     }
*** End Patch
PATCH
 && submit-patch && printf '%s\n' '; Make sure this does not crash.' 'define void @test(ptr %arg) {' ';' '  %a = alloca i32' '  store ptr %a, ptr %arg' '  store i1 true, ptr poison' '  call void @llvm.lifetime.end.p0(i64 4, ptr %a)' '  ret void' '}' > /tmp/test.ll && /llvm-autofix/build/llvm-build/150338/bin/opt -S -passes=instcombine /tmp/test.ll || true
