```bash
sed -i '483,488c\    if (II->isLifetimeStartOrEnd()) {
      auto *Arg = II->getArgOperand(1);
      // If the value does not have a materialized use list, there are no recorded
      // uses to inspect. Conservatively consider the intrinsic not trivially dead.
      if (!Arg->hasUseList())
        return false;
      // If the only uses of the alloca are lifetime intrinsics, then the intrinsics are dead.
      return llvm::all_of(Arg->users(), [](User *U) { return isa<LifetimeIntrinsic>(U); });
    }' /llvm-autofix-deps/llvm/llvm/llvm/lib/Transforms/Utils/Local.cpp && nl -ba /llvm-autofix-deps/llvm/llvm/llvm/lib/Transforms/Utils/Local.cpp | sed -n '480,500p' && submit-patch
